import type { Book, BookInput, BookFilters, ReadingStats } from './types'

const DATA_PATH = './data/books.json'

export const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Book[]
}

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2))
}

export const addBook = async (input: BookInput): Promise<Book> => {
  const books = await loadBooks()
  const book: Book = {
    id: crypto.randomUUID(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    coverUrl: input.coverUrl,
    currentPage: 0,
    status: 'want-to-read',
    addedAt: new Date().toISOString(),
  }
  books.push(book)
  await saveBooks(books)
  return book
}

export const updateProgress = async (id: string, currentPage: number): Promise<Book> => {
  const books = await loadBooks()
  const index = books.findIndex((b) => b.id === id)
  if (index === -1) throw new Error(`Book not found: ${id}`)

  const book = books[index]
  const clampedPage = Math.max(0, Math.min(currentPage, book.pageCount))
  book.currentPage = clampedPage

  if (clampedPage >= book.pageCount && book.status !== 'completed') {
    book.status = 'completed'
    book.completedAt = new Date().toISOString()
  } else if (clampedPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading'
  }

  books[index] = book
  await saveBooks(books)
  return book
}

export const updateStatus = async (id: string, status: Book['status']): Promise<Book> => {
  const books = await loadBooks()
  const index = books.findIndex((b) => b.id === id)
  if (index === -1) throw new Error(`Book not found: ${id}`)

  const book = books[index]
  book.status = status

  if (status === 'completed') {
    book.currentPage = book.pageCount
    book.completedAt = book.completedAt ?? new Date().toISOString()
  }

  books[index] = book
  await saveBooks(books)
  return book
}

export const removeBook = async (id: string): Promise<void> => {
  const books = await loadBooks()
  const filtered = books.filter((b) => b.id !== id)
  if (filtered.length === books.length) throw new Error(`Book not found: ${id}`)
  await saveBooks(filtered)
}

export const getBooks = async (filters?: BookFilters): Promise<Book[]> => {
  let books = await loadBooks()

  if (filters?.status) {
    books = books.filter((b) => b.status === filters.status)
  }
  if (filters?.genre) {
    books = books.filter((b) => b.genre.toLowerCase() === filters.genre!.toLowerCase())
  }

  return books
}

export const getGenres = async (): Promise<string[]> => {
  const books = await loadBooks()
  const genres = new Set(books.map((b) => b.genre))
  return [...genres].sort()
}

export const getStats = async (): Promise<ReadingStats> => {
  const books = await loadBooks()
  const completed = books.filter((b) => b.status === 'completed').length
  const reading = books.filter((b) => b.status === 'reading').length
  const wantToRead = books.filter((b) => b.status === 'want-to-read').length
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) /
        books.length
      : 0

  return {
    totalBooks: books.length,
    completed,
    reading,
    wantToRead,
    totalPagesRead,
    averageProgress: Math.round(averageProgress * 100),
  }
}

