    status === 'want-to-read'
      ? styles.badgeWant
      : status === 'reading'
        ? styles.badgeReading
        : styles.badgeCompleted
  return { ...base, ...variant }
}

const statusLabel = (status: Book['status']): string =>
  status === 'want-to-read' ? 'Want to Read' : status === 'reading' ? 'Reading' : 'Completed'

const renderProgressBar = (book: Book) => {
  const pct = book.pageCount > 0 ? Math.round((book.currentPage / book.pageCount) * 100) : 0
  return h(Fragment, {},
    h('div', { style: styles.progressContainer },
      h('div', { style: styles.progressBar(pct) }),
    ),
    h('div', { style: styles.progressText },
      `${book.currentPage} / ${book.pageCount} pages (${pct}%)`,
    ),
  )
}

