import type { BookFilters, ReadingStatus } from './types'
import {
  addBook,
  getBooks,
  getGenres,
  getStats,
  removeBook,
  updateProgress,
  updateStatus,
} from './store'
import { renderReadingList } from './render'

const parseFilters = (url: URL): BookFilters => {
  const status = url.searchParams.get('status') as ReadingStatus | null
  const genre = url.searchParams.get('genre')
  return {
    ...(status && status !== 'all' ? { status } : {}),
    ...(genre ? { genre } : {}),
  }
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string) =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export default {
  port: 3000,

  async fetch(req: Request): Promise<Response> {
    const url = new URL(req.url)
    const method = req.method

    // GET / — render the reading list page
    if (method === 'GET' && url.pathname === '/') {
      const filters = parseFilters(url)
      const [books, stats, genres] = await Promise.all([
        getBooks(filters),
        getStats(),
        getGenres(),
      ])
      return htmlResponse(renderReadingList(books, stats, filters, genres))
    }

    // GET /api/books — list books with optional filters
    if (method === 'GET' && url.pathname === '/api/books') {
      const filters = parseFilters(url)
      const books = await getBooks(filters)
      return jsonResponse(books)
    }

    // POST /api/books — add a book
    if (method === 'POST' && url.pathname === '/api/books') {
      const body = await req.json()
      const { title, author, genre, pageCount, coverUrl } = body
      if (!title || !author || !genre || !pageCount) {
        return jsonResponse({ error: 'title, author, genre, and pageCount are required' }, 400)
      }
      const book = await addBook({
        title,
        author,
        genre,
        pageCount: Number(pageCount),
        coverUrl: coverUrl ?? '',
      })
      return jsonResponse(book, 201)
    }

    // PATCH /api/books/:id/progress — update reading progress
    if (method === 'PATCH' && url.pathname.match(/^\/api\/books\/[^/]+\/progress$/)) {
      const id = url.pathname.split('/')[3]
      const { currentPage } = await req.json()
      if (currentPage === undefined) {
        return jsonResponse({ error: 'currentPage is required' }, 400)
      }
      const book = await updateProgress(id, Number(currentPage))
      return jsonResponse(book)
    }

    // PATCH /api/books/:id/status — update reading status
    if (method === 'PATCH' && url.pathname.match(/^\/api\/books\/[^/]+\/status$/)) {
      const id = url.pathname.split('/')[3]
      const { status } = await req.json()
      if (!status || !['want-to-read', 'reading', 'completed'].includes(status)) {
        return jsonResponse({ error: 'status must be want-to-read, reading, or completed' }, 400)
      }
      const book = await updateStatus(id, status as ReadingStatus)
      return jsonResponse(book)
    }

    // DELETE /api/books/:id — remove a book
    if (method === 'DELETE' && url.pathname.match(/^\/api\/books\/[^/]+$/)) {
      const id = url.pathname.split('/')[3]
      await removeBook(id)
      return jsonResponse({ ok: true })
    }

    // GET /api/stats — reading statistics
    if (method === 'GET' && url.pathname === '/api/stats') {
      const stats = await getStats()
      return jsonResponse(stats)
    }

    // GET /api/genres — list all genres
    if (method === 'GET' && url.pathname === '/api/genres') {
      const genres = await getGenres()
      return jsonResponse(genres)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
}

export type Category = 'length' | 'weight' | 'temperature' | 'volume' | 'time'

type UnitDef = {
  label: string
  symbol: string
  toBase: number
}

type TempUnit = {
  label: string
  symbol: string
}

const lengthUnits: Record<string, UnitDef> = {
  mm:  { label: 'Millimeters', symbol: 'mm', toBase: 0.001 },
  cm:  { label: 'Centimeters', symbol: 'cm', toBase: 0.01 },
  m:   { label: 'Meters',      symbol: 'm',  toBase: 1 },
  km:  { label: 'Kilometers',  symbol: 'km', toBase: 1000 },
  in:  { label: 'Inches',      symbol: 'in', toBase: 0.0254 },
  ft:  { label: 'Feet',        symbol: 'ft', toBase: 0.3048 },
  yd:  { label: 'Yards',       symbol: 'yd', toBase: 0.9144 },
  mi:  { label: 'Miles',       symbol: 'mi', toBase: 1609.344 },
}

const weightUnits: Record<string, UnitDef> = {
  mg: { label: 'Milligrams', symbol: 'mg', toBase: 0.001 },
  g:  { label: 'Grams',      symbol: 'g',  toBase: 1 },
  kg: { label: 'Kilograms',  symbol: 'kg', toBase: 1000 },
  lb: { label: 'Pounds',     symbol: 'lb', toBase: 453.592 },
  oz: { label: 'Ounces',     symbol: 'oz', toBase: 28.3495 },
}

const temperatureUnits: Record<string, TempUnit> = {
  C: { label: 'Celsius',    symbol: '°C' },
  F: { label: 'Fahrenheit', symbol: '°F' },
  K: { label: 'Kelvin',     symbol: 'K' },
}

const volumeUnits: Record<string, UnitDef> = {
  ml:   { label: 'Milliliters',  symbol: 'ml',   toBase: 1 },
  l:    { label: 'Liters',       symbol: 'L',    toBase: 1000 },
  gal:  { label: 'Gallons',      symbol: 'gal',  toBase: 3785.41 },
  qt:   { label: 'Quarts',       symbol: 'qt',   toBase: 946.353 },
  pt:   { label: 'Pints',        symbol: 'pt',   toBase: 473.176 },
  cup:  { label: 'Cups',         symbol: 'cup',  toBase: 236.588 },
  tbsp: { label: 'Tablespoons',  symbol: 'tbsp', toBase: 14.7868 },
  tsp:  { label: 'Teaspoons',    symbol: 'tsp',  toBase: 4.92892 },
}

const timeUnits: Record<string, UnitDef> = {
  ms:   { label: 'Milliseconds', symbol: 'ms',   toBase: 0.001 },
  s:    { label: 'Seconds',      symbol: 's',    toBase: 1 },
  min:  { label: 'Minutes',      symbol: 'min',  toBase: 60 },
  hr:   { label: 'Hours',        symbol: 'hr',   toBase: 3600 },
  day:  { label: 'Days',         symbol: 'day',  toBase: 86400 },
  week: { label: 'Weeks',        symbol: 'week', toBase: 604800 },
}

const linearUnitsMap: Record<string, Record<string, UnitDef>> = {
  length: lengthUnits,
  weight: weightUnits,
  volume: volumeUnits,
  time: timeUnits,
}

export type UnitInfo = {
  key: string
  label: string
  symbol: string
}

export const getUnitsForCategory = (category: Category): UnitInfo[] => {
  if (category === 'temperature') {
    return Object.entries(temperatureUnits).map(([key, u]) => ({
      key,
      label: u.label,
      symbol: u.symbol,
    }))
  }
  const units = linearUnitsMap[category]
  return Object.entries(units).map(([key, u]) => ({
    key,
    label: u.label,
    symbol: u.symbol,
  }))
}

export const categories: { key: Category; label: string }[] = [
  { key: 'length', label: 'Length' },
  { key: 'weight', label: 'Weight' },
  { key: 'temperature', label: 'Temperature' },
  { key: 'volume', label: 'Volume' },
  { key: 'time', label: 'Time' },
]

const convertTemperature = (value: number, from: string, to: string): number => {
  if (from === to) return value
  // Convert to Celsius first
  let celsius: number
  if (from === 'C') celsius = value
  else if (from === 'F') celsius = (value - 32) * 5 / 9
  else celsius = value - 273.15 // K

  // Convert from Celsius to target
  if (to === 'C') return celsius
  if (to === 'F') return celsius * 9 / 5 + 32
  return celsius + 273.15 // K
}

const getTemperatureFormula = (from: string, to: string): string => {
  if (from === to) return `${temperatureUnits[to].symbol} = ${temperatureUnits[from].symbol}`
  const f = temperatureUnits[from].symbol
  const t = temperatureUnits[to].symbol
  const formulas: Record<string, string> = {
    'C-F': `${t} = (${f} × 9/5) + 32`,
    'C-K': `${t} = ${f} + 273.15`,
    'F-C': `${t} = (${f} - 32) × 5/9`,
    'F-K': `${t} = (${f} - 32) × 5/9 + 273.15`,
    'K-C': `${t} = ${f} - 273.15`,
    'K-F': `${t} = (${f} - 273.15) × 9/5 + 32`,
  }
  return formulas[`${from}-${to}`] ?? ''
}

const convertLinear = (value: number, from: string, to: string, units: Record<string, UnitDef>): number => {
  if (from === to) return value
  const baseValue = value * units[from].toBase
  return baseValue / units[to].toBase
}

const getLinearFormula = (from: string, to: string, units: Record<string, UnitDef>): string => {
  if (from === to) return `${units[to].symbol} = ${units[from].symbol}`
  const factor = units[from].toBase / units[to].toBase
  const formatted = formatNumber(factor)
  return `${units[to].symbol} = ${units[from].symbol} × ${formatted}`
}

const formatNumber = (n: number): string => {
  if (Number.isInteger(n)) return n.toString()
  // Show up to 6 significant digits, strip trailing zeros
  return parseFloat(n.toPrecision(6)).toString()
}

export type ConversionResult = {
  input: number
  output: number
  fromSymbol: string
  toSymbol: string
  formula: string
  formatted: string
}

export const convert = (category: Category, value: number, from: string, to: string): ConversionResult => {
  let output: number
  let formula: string
  let fromSymbol: string
  let toSymbol: string

  if (category === 'temperature') {
    output = convertTemperature(value, from, to)
    formula = getTemperatureFormula(from, to)
    fromSymbol = temperatureUnits[from].symbol
    toSymbol = temperatureUnits[to].symbol
  } else {
    const units = linearUnitsMap[category]
    output = convertLinear(value, from, to, units)
    formula = getLinearFormula(from, to, units)
    fromSymbol = units[from].symbol
    toSymbol = units[to].symbol
  }

  return {
    input: value,
    output,
    fromSymbol,
    toSymbol,
    formula,
    formatted: formatNumber(output),
  }
}

