import { type Category, convert, getUnitsForCategory } from './converter.ts'
import { renderPage } from './view.ts'

const validCategories = new Set<Category>(['length', 'weight', 'temperature', 'volume', 'time'])

const isValidCategory = (val: string | null): val is Category =>
  val !== null && validCategories.has(val as Category)

const parseQuery = (url: URL) => {
  const category = url.searchParams.get('category')
  const value = url.searchParams.get('value')
  const from = url.searchParams.get('from')
  const to = url.searchParams.get('to')
  return { category, value, from, to }
}

const isValidUnit = (unit: string | null, category: Category): boolean => {
  if (!unit) return false
  const units = getUnitsForCategory(category)
  return units.some(u => u.key === unit)
}

export const handleRequest = (req: Request): Response => {
  const url = new URL(req.url)
  const path = url.pathname

  if (path === '/' || path === '') {
    const { category } = parseQuery(url)
    const activeCategory: Category = isValidCategory(category) ? category : 'length'
    const html = renderPage(activeCategory)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  if (path === '/convert') {
    const { category, value, from, to } = parseQuery(url)
    const activeCategory: Category = isValidCategory(category) ? category : 'length'

    if (!value || !from || !to || isNaN(Number(value))) {
      const html = renderPage(activeCategory)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (!isValidUnit(from, activeCategory) || !isValidUnit(to, activeCategory)) {
      const html = renderPage(activeCategory)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    const numericValue = Number(value)
    const result = convert(activeCategory, numericValue, from, to)

    const accept = req.headers.get('accept') ?? ''
    if (accept.includes('application/json')) {
      return new Response(JSON.stringify(result), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    const html = renderPage(activeCategory, result, from, to, value)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  return new Response('Not Found', { status: 404 })
}
